也许你注意到，我刚刚配置的是 http connector，而且也没有给 nexus 配置 ssl。如果不想配置，可以直接使用刚刚的 8082 端口使用了。 这里是我的 nginx 配置，注意替换 server_name，和 nexus 的地址，大家参考着来。这样配置，可以让 docker 仓库 、其他仓库(maven)和 webui 共用地址。 server
    {
        listen 80;
        listen [::]:80;
        server_name nexus.example.com ;
        return 301 https://$host$request_uri;

        access_log off;
    }

server
    {
        listen 443 ssl http2;
        listen [::]:443 ssl http2;
        server_name nexus.example.com ;

        # 证书部分
        ssl_certificate /etc/ssl//fullchain.cer;
        ssl_certificate_key /etc/ssl/cert.key;

        # TLS 握手优化
        ssl_session_cache builtin:1000 shared:SSL:10m;
        ssl_session_timeout 5m;
        keepalive_timeout 75s;
        keepalive_requests 100;
        #ssl_session_tickets off;
        ssl_ecdh_curve secp384r1;

        # TLS 版本控制
        ssl_protocols TLSv1.2 TLSv1.3;
        ssl_prefer_server_ciphers on;
        ssl_ciphers TLS13-CHACHA20-POLY1305-SHA256:TLS13-AES-256-GCM-SHA384:TLS13-AES-128-GCM-SHA256:EECDH+CHACHA20:EECDH+AESGCM:EECDH+AES;

        # 开启 1.3 0-RTT
        ssl_early_data on;

        # SSL Stapling
        ssl_stapling on;
        ssl_stapling_verify on;
        resolver 223.5.5.5 1.1.1.1 1.0.0.1 valid=300s;
        resolver_timeout 5s;

        add_header Strict-Transport-Security "max-age=63072000; includeSubDomains; preload" always;

        proxy_send_timeout 120;
        proxy_read_timeout 300;
        proxy_buffering    off;
        proxy_request_buffering off;
        tcp_nodelay        on;

        client_max_body_size 0;

        location / {
            proxy_pass http://nexus:8081;
            proxy_set_header Host $host;
            proxy_set_header X-Real-IP $remote_addr;
            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
            proxy_set_header X-Forwarded-Proto "https";
        }

        # 将 /v2/ 转到创建的docker http connector
        location /v2/ {
            proxy_pass http://nexus:8082;
            proxy_set_header Host $host;
            proxy_set_header X-Real-IP $remote_addr;
            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
            proxy_set_header X-Forwarded-Proto "https";
        }

        access_log off;
    }

