                    listPoint.EndUpdate();

                    txtX.Text = "";
                    txtY.Text = "";
                    txtX.Focus();
                }
                else
                {
                    MessageBox.Show("请输入数字！");
                    txtX.Text = "";
                    txtY.Text = "";
                    txtX.Focus();
                }
            }
