        private void btnCalcu_Click(object sender, EventArgs e)
        {
            if (list.Count >= 3)
            {
                //将线首加入列表，保证多边形闭合
                list.Add(list[0]);

                //计算面积
                double area = 0;

                //根据公式进行计算
                for (int i = 0; i < list.Count - 1; i++)
                {
                    area += (list[i].X +list[i+1].X) * (list[i + 1].Y - list[i].Y);
                }

                //保证面积为正
                area = Math.Abs(area / 2);
                txtResult.Text = "面积：" + area.ToString("0.0");
