遍历字符串。 当没有遇见重复字符，则将当前字符拼入临时字符串。当遇见了重复字符，将临时字符串中重复字符及以前的字符串移除，然后将当前字符拼入临时字符串。如果此时临时字符串长度大于记录的最大长度，则更新最大长度。 所以总的来说，只需要遍历一遍字符串即可。 /**
 * @param {string} s
 * @return {number}
 */
var lengthOfLongestSubstring = function (s) {
  if (!s) {
    return 0;
  }
  let result = 0;
  let tmp = "";
  for (let i = 0; i < s.length; i++) {
    const index = tmp.indexOf(s[i]);
    if (index === -1) {
      tmp += s[i];
      if (tmp.length > result) {
        result = tmp.length;
      }
    } else {
      tmp = tmp.substring(index + 1) + s[i];
    }
  }
  return result;
}; html pre.shiki code .ss7Ak, html code.shiki .ss7Ak{--shiki-light:#90A4AE;--shiki-light-font-style:italic;--shiki-default:#6A737D;--shiki-default-font-style:inherit;--shiki-dark:#6A737D;--shiki-dark-font-style:inherit;--shiki-sepia:#88846F;--shiki-sepia-font-style:inherit}html pre.shiki code .s3PD0, html code.shiki .s3PD0{--shiki-light:#39ADB5;--shiki-light-font-style:italic;--shiki-default:#D73A49;--shiki-default-font-style:inherit;--shiki-dark:#F97583;--shiki-dark-font-style:inherit;--shiki-sepia:#66D9EF;--shiki-sepia-font-style:italic}html pre.shiki code .sYAMa, html code.shiki .sYAMa{--shiki-light:#9C3EDA;--shiki-light-font-style:italic;--shiki-default:#D73A49;--shiki-default-font-style:inherit;--shiki-dark:#F97583;--shiki-dark-font-style:inherit;--shiki-sepia:#66D9EF;--shiki-sepia-font-style:italic}html pre.shiki code .sbCpd, html code.shiki .sbCpd{--shiki-light:#39ADB5;--shiki-light-font-style:italic;--shiki-light-text-decoration:inherit;--shiki-default:#6F42C1;--shiki-default-font-style:inherit;--shiki-default-text-decoration:inherit;--shiki-dark:#B392F0;--shiki-dark-font-style:inherit;--shiki-dark-text-decoration:inherit;--shiki-sepia:#A6E22E;--shiki-sepia-font-style:inherit;--shiki-sepia-text-decoration:underline}html pre.shiki code .sbmyj, html code.shiki .sbmyj{--shiki-light:#E2931D;--shiki-light-font-style:italic;--shiki-light-text-decoration:inherit;--shiki-default:#6F42C1;--shiki-default-font-style:inherit;--shiki-default-text-decoration:inherit;--shiki-dark:#B392F0;--shiki-dark-font-style:inherit;--shiki-dark-text-decoration:inherit;--shiki-sepia:#A6E22E;--shiki-sepia-font-style:inherit;--shiki-sepia-text-decoration:underline}html pre.shiki code .sie0N, html code.shiki .sie0N{--shiki-light:#90A4AE;--shiki-light-font-style:italic;--shiki-default:#24292E;--shiki-default-font-style:inherit;--shiki-dark:#E1E4E8;--shiki-dark-font-style:inherit;--shiki-sepia:#F8F8F2;--shiki-sepia-font-style:inherit}html pre.shiki code .srJo8, html code.shiki .srJo8{--shik