一个基础的 Promise function testPromise() {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      resolve("成功！");
    }, 1000);
    setTimeout(() => {
      reject("失败！");
    }, 3000);
  })
    .then((res) => {
      console.log("then:", res);
      return "then return";
    })
    .catch((err) => {
      console.log("catch:", err);
      return "catch return";
    })
    .finally((res) => {
      console.log("finally", res);
      return "finally return";
    });
}
testPromise(); 一个 promise 中，resolve 和 reject 只会执行最先触发的一个

多次添加then、catch、finally方法。 function testPromise() {
  return new Promise((resolve, reject) => {
    resolve("成功！");
  })
    .then((res) => {
      console.log("then 1:", res);
      return "then 1 return";
    })
    .catch((err) => {
      console.log("catch 1:", err);
      return "catch 1 return";
    })
    .finally((res) => {
      console.log("finally 1", res);
      return "finally 1 return";
    })
    .then((res) => {
      console.log("then 2:", res);
      return "then 2 return";
    })
    .catch((err) => {
      console.log("catch 2:", err);
      return "catch 2 return";
    })
    .finally((res) => {
      console.log("finally 2", res);
      return "finally 2 return";
    })
    .then((res) => {
      console.log("then 3:", res);
      return "then 3 return";
    })
    .catch((err) => {
      console.log("catch 3:", err);
      return "catch 3 return";
    })
    .finally((res) => {
      console.log("finally 3", res);
      return "finally 3 return";
    });
}
testPromise(); 运行结果 第一个 then 的参数是 resolve 的参数值，然后执行第一个 finally第二个 then 的回调参数是第一个 then 的返回值，然后执行第二个 finally，以此类推finally 无参数

