      return "then 3 return";
    })
    .catch((err) => {
      console.log("catch 3:", err);
      return "catch 3 return";
    })
    .finally((res) => {
      console.log("finally 3", res);
      return "finally 3 return";
    });
}
testPromise(); 在 resolve 后，抛出错误不会被处理，与 reject 处理相似在第一个 then 中抛出错误，被后续的第一个 catch（catch1）捕获，参数是错误值，后续继续执行。在第一个 catch 中抛出错误，被后续的第一个 catch（catch2）捕获，参数是错误值，后续继续执行。在第二个 finally 中抛出错误，被后续的第一个 catch（catch3）捕获，参数是错误值，后续继续执行。

function testPromise() {
  const a = new Promise((resolve, reject) => {
    resolve("成功！");
  });
  const b = a.finally((res) => {
    console.log("finally 1", res);
    return "finally 1 return";
  });
  const c = a.then((res) => {
    console.log("then 1:", res);
    throw new Error("then 1 throw");
  });
  const d = a.catch((err) => {
    console.log("catch 1:", err);
    throw new Error("catch 1 throw");
  });
  const e = a.catch((err) => {
    console.log("catch 2:", err);
  });
  console.log("a === b", a === b);
  console.log("a === c", a === c);
  console.log("a === d", a === d);
}
testPromise(); then、finally、catch 返回的都是一个新的 Promise，所以 a、b、c、d、e 的值都是不同的在 a 上添加的 catch 仅会处理 a 的 reject 和错误，不会处理 then 和 finally 的错误then、finally 执行是按照事件添加顺序

分别在 a 和 a.then 上添加 then、catch、finally function testPromise() {
  const a = new Promise((resolve, reject) => {
    resolve("成功！");
  });
  const b = a.then((res) => {
    console.log("then 1:", res);
    return "then 1 return";
  });
  a.catch((err) => {
    console.log("catch 1:", err);
    return "catch 1 return";
  });
  a.finally((res) => {
    console.log("finally 1", res);
    return "finally 1 return";
  });
  b.then((res) => {
    console.log("then 2:", res);
    return "then 2 return";
  });
  b.catch((err) => {
    console.log("catch 2:", err);
    return "catch 2 return";
  });
  b.finally((res) => {
    console.log("finally 2", res);
    return "finally 2 return";
  });
  a.then((res) => {
    console.log("then 3:", res);
    return "then 3 return";
  });
  a.catch((err) => {
    console.log("catch 3:", err);
    return "catch 3 return";
  });
  a.finally((res) => {
    console.log("finally 3", res);
    return "finally 3 return";
  });
}
testPromise(); 将 a.then 的返回值保存为 b，可以看到 b 上添加的 then、catch、finally 执行必然在 a 上添加的 then、catch、finally 之后执行在同一个 Promise 对象上多次添加 then、catch、finally，也会按照添加顺序依次执行

上一节的 main.js，我把它称为"主模块"，意思是整个网页的入口代码。它有点像 C 语言的 main()函数，所有代码都从这儿开始运行。 下面就来看，怎么写 main.js。 如果我们的代码不依赖任何其他模块，那么可以直接写入 javascript 代码。 // main.js

alert("加载成功！"); 但这样的话，就没必要使用 require.js 了。真正常见的情况是，主模块依赖于其他模块，这时就要使用 AMD 规范定义的的 require()函数。 // main.js

require(["moduleA", "moduleB", "moduleC"], function (
  moduleA,
  moduleB,
  moduleC
) {
  // some code here
}); require()函数接受两个参数。第一个参数是一个数组，表示所依赖的模块，上例就是'moduleA', 'moduleB', 'moduleC'，即主模块依赖这三个模块；第二个参数是一个回调函数，当前面指定的模块都加载成功后，它将被调用。加载的模块会以参数形式传入该函数，从而在回调函数内部就可以使用这些模块。 require()异步加载 moduleA，moduleB 和 moduleC，浏览器不会失去响应；它指定的回调函数，只有前面的模块都加载成功后，才会运行，解决了依赖性的问题。 下面，我们看一个实际的例子。 假定主模块依赖 jquery、underscore 和 backbone 这三个模块，main.js 就可以这样写： require(["jquery", "underscore", "backbone"], function ($, _, Backbone) {
  // some code here
}); require.js 会先加载 jQuery、underscore 和 backbone，然后再运行回调函数。主模块的代码就写在回调函数中。

上一节最后的示例中，主模块的依赖模块是'jquery', 'underscore', 'backbone'。默认情况下，require.js 假定这三个模块与 main.js 在同一个目录，文件名分别为 jquery.js，underscore.js 和 backbone.js，然后自动加载。 使用 require.config()方法，我们可以对模块的加载行为进行自定义。require.config()就写在主模块（main.js）的头部。参数就是一个对象，这个对象的 paths 属性指定各个模块的加载路径。 require.config({
  paths: {
    jquery: "jquery.min",
    underscore: "underscore.min",
    backbone: "backbone.min",
  },
}); 上面的代码给出了三个模块的文件名，路径默认与 main.js 在同一个目录（js 子目录）。如果这些模块在其他目录，比如 js/lib 目录，则有两种写法。一种是逐一指定路径。 require.config({
  paths: {
    jquery: "lib/jquery.min",
    underscore: "lib/underscore.min",
    backbone: "lib/backbone.min",
  },
}); 另一种则是直接改变基目录（baseUrl）。 require.config({
  baseUrl: "js/lib",

  paths: {
    jquery: "jquery.min",
    underscore: "underscore.min",
    backbone: "backbone.min",
  },
}); 如果某个模块在另一台主机上，也可以直接指定它的网址，比如： require.config({
  paths: {
    jquery: "https://ajax.googleapis.com/ajax/libs/jquery/1.7.2/jquery.min",
  },
}); require.js 要求，每个模块是一个单独的 js 文件。这样的话，如果加载多个模块，就会发出多次 HTTP 请求，会影响网页的加载速度。因此，require.js 提供了一个优化工具，当模块部署完毕以后，可以用这个工具将多个模块合并在一个文件中，减少 HTTP 请求数。

require.js 加载的模块，采用 AMD 规范。也就是说，模块必须按照 AMD 的规定来写。 具体来说，就是模块必须采用特定的 define()函数来定义。如果一个模块不依赖其他模块，那么可以直接定义在 define()函数之中。 假定现在有一个 math.js 文件，它定义了一个 math 模块。那么，math.js 就要这样写： // math.js

define(function () {
  var add = function (x, y) {
    return x + y;
  };

  return {
    add: add,
  };
}); 加载方法如下： // main.js

require(["math"], function (math) {
  alert(math.add(1, 1));
}); 如果这个模块还依赖其他模块，那么 define()函数的第一个参数，必须是一个数组，指明该模块的依赖性。 define(["myLib"], function (myLib) {
  function foo() {
    myLib.doSomething();
  }

  return {
    foo: foo,
  };
}); 当 require()函数加载上面这个模块的时候，就会先加载 myLib.js 文件。

理论上，require.js 加载的模块，必须是按照 AMD 规范、用 define()函数定义的模块。但是实际上，虽然已经有一部分流行的函数库（比如 jQuery）符合 AMD 规范，更多的库并不符合。那么，require.js 是否能够加载非规范的模块呢？ 回答是可以的。 这样的模块在用 require()加载之前，要先用 require.config()方法，定义它们的一些特征。 举例来说，underscore 和 backbone 这两个库，都没有采用 AMD 规范编写。如果要加载它们的话，必须先定义它们的特征。 require.config({
  shim: {
    underscore: {
      exports: "_",
    },

    backbone: {
      deps: ["underscore", "jquery"],
      exports: "Backbone",
    },
  },
}); require.config()接受一个配置对象，这个对象除了有前面说过的 paths 属性之外，还有一个 shim 属性，专门用来配置不兼容的模块。具体来说，每个模块要定义（1）exports 值（输出的变量名），表明这个模块外部调用时的名称；（2）deps 数组，表明该模块的依赖性。 比如，jQuery 的插件可以这样定义： shim: {

　　　　'jquery.scroll': {

　　　　　　deps: ['jquery'],

　　　　　　exports: 'jQuery.fn.scroll'

　　　　}

　　}

require.js 还提供一系列插件，实现一些特定的功能。 domready 插件，可以让回调函数在页面 DOM 结构加载完成后再运行。 require(["domready!"], function (doc) {
  // called once the DOM is ready
}); text 和 image 插件，则是允许 require.js 加载文本和图片文件。 define(["text!review.txt", "image!cat.jpg"], function (review, cat) {
  console.log(review);

  document.body.appendChild(cat);
}); 类似的插件还有 json 和 mdown，用于加载 json 文件和 markdown 文件。 （完） html pre.shiki code .swvn1, html code.shiki .swvn1{--shiki-light:#39ADB5;--shiki-default:#24292E;--shiki-dark:#E1E4E8;--shiki-sepia:#F8F8F2}html pre.shiki code .sHsBP, html code.shiki .sHsBP{--shiki-light:#E53935;--shiki-default:#22863A;--shiki-dark:#85E89D;--shiki-sepia:#F92672}html pre.shiki code .s_lYk, html code.shiki .s_lYk{--shiki-light:#9C3EDA;--shiki-default:#6F42C1;--shiki-dark:#B392F0;--shiki-sepia:#A6E22E}html pre.shiki code .siCPE, html code.shiki .siCPE{--shiki-light:#39ADB5;--shiki-default:#032F62;--shiki-dark:#9ECBFF;--shiki-sepia:#E6DB74}html pre.shiki code .sLACW, html code.shiki .sLACW{--shiki-light:#91B859;--shiki-default:#032F62;--shiki-dark:#9ECBFF;--shiki-sepia:#E6DB74}html .light .shiki span {color: var(--shiki-light);background: var(--shiki-light-bg);font-style: var(--shiki-light-font-style);font-weight: var(--shiki-light-font-weight);text-decoration: var(--shiki-light-text-decoration);}html.light .shiki span {color: var(--shiki-light);background: var(--shiki-light-bg);font-style: var(--shiki-light-font-style);font-weight: var(--shiki-light-font-weight);text-decoration: var(--shiki-light-text-decoration);}html .default .shiki span {color: var(--shiki-default);background: var(--shiki-default-bg);font-style: var(--shiki-default-font-style);font-weight: var(--shiki-default-font-weight);text-decoration: var(--shiki-default-text-decoration);}html .shiki span {color: var(--shiki-default);background: var(--shiki-default-bg);font-style: var(--shiki-default-font-style);font-weight: var(--shiki-default-font-weight);text-decoration: var(--shiki-default-text-decoration);}html .dark .shiki span {color: var(--shiki-dark);background: var(--shiki-dark-bg);font-style: var(--shiki-dark-font-style);font-weight: var(--shiki-dark-font-weight);text-decoration: var(--shiki-dark-text-decoration);}html.dark .shiki span {color: var(--shiki-dark);background: var(--shiki-dark-bg);font-style: var(--shiki-dark-font-s